// src/components/UI/Button/index.jsx

import React from 'react';
import s from './Button.module.css';

const Button = ({ children, type = 'primary', onClick, className, disabled = false }) => {

  // Комбинируем общие стили и стили для конкретного типа (primary, secondary и т.д.)
  const buttonClass = `${s.button} ${s[type]} ${className || ''}`;

  return (
    <button 
      className={buttonClass} 
      onClick={onClick} 
      disabled={disabled}
    >
      {children}
    </button>
  );
};

export default Button;
